        $tags = Tag::all();
        $authorIds = Author::pluck('id')->toArray();
        $hourOffset = 1;

        foreach ($articlesByCategory as $categoryId => $catArticles) {
            foreach ($catArticles as $articleData) {
                $articleData['category_id'] = $categoryId;
                $articleData['author_id'] = $articleData['author_id'] ?? $authorIds[array_rand($authorIds)];
                $articleData['status'] = 'published';
                $articleData['published_at'] = now()->subHours($hourOffset);
                $hourOffset += rand(1, 4);

                $article = Article::create($articleData);
                $article->tags()->attach($tags->random(rand(2, 4))->pluck('id'));
            }
        }
    }
